CREATE VIEW `ads_short_video_log_epis_history_view` (`dt` COMMENT "日期，根据CreateTime转换而来", `id` COMMENT "主键id", `account_id` COMMENT "用户id", `series_id` COMMENT "剧id", `epis_id` COMMENT "集id", `watch_stamp` COMMENT "观看时间戳", `create_time` COMMENT "创建时间", `epis_num` COMMENT "集数", `region_id` COMMENT "归属区域 id，1：香港，2：北美；", `watch_over` COMMENT "是否观看完成")
COMMENT "短剧域海外短剧有效观看记录视图" AS (SELECT `t1`.`dt`, `t1`.`Id`, `t1`.`AccountId`, `t1`.`SeriesId`, `t1`.`EpisId`, `t1`.`WatchStamp`, `t1`.`CreateTime`, `t1`.`EpisNum`, `t1`.`regionId`, `t1`.`WatchOver`
FROM (SELECT `t`.`dt`, `t`.`Id`, `t`.`AccountId`, `t`.`SeriesId`, `t`.`EpisId`, `t`.`WatchStamp`, `t`.`CreateTime`, `t`.`EpisNum`, `t`.`regionId`, `t`.`WatchOver`, row_number() OVER (PARTITION BY `t`.`Id` ORDER BY `t`.`CreateTime` ASC ) AS `rn`
FROM (SELECT date(`ods`.`ods_tidb_short_video_log_epis_history`.`CreateTime`) AS `dt`, `ods`.`ods_tidb_short_video_log_epis_history`.`Id`, `ods`.`ods_tidb_short_video_log_epis_history`.`AccountId`, `ods`.`ods_tidb_short_video_log_epis_history`.`SeriesId`, `ods`.`ods_tidb_short_video_log_epis_history`.`EpisId`, `ods`.`ods_tidb_short_video_log_epis_history`.`WatchStamp`, `ods`.`ods_tidb_short_video_log_epis_history`.`CreateTime`, `ods`.`ods_tidb_short_video_log_epis_history`.`EpisNum`, NULL AS `regionId`, NULL AS `WatchOver`
FROM `ods`.`ods_tidb_short_video_log_epis_history` UNION ALL SELECT `ods`.`a`.`dt`, `ods`.`a`.`Id`, `ods`.`a`.`AccountId`, `ods`.`a`.`SeriesId`, `ods`.`a`.`EpisId`, if(`ods`.`a`.`WatchOver` = 1, `dim`.`b`.`duration`, `ods`.`a`.`WatchStamp`) AS `WatchStamp`, `ods`.`a`.`CreateTime`, `ods`.`a`.`EpisNum`, `ods`.`a`.`regionId`, `ods`.`a`.`WatchOver`
FROM `ods`.`ods_tidb_short_video_log_ext_epis_history_part2` AS `a` LEFT OUTER JOIN `dim`.`dim_short_video_epis_view` AS `b` ON `ods`.`a`.`EpisId` = `dim`.`b`.`epis_id`) `t`) `t1`
WHERE `t1`.`rn` = 1);